bel></div><label class="field"><span>Nova senha</span><input type="password" name="password" minlength="8" placeholder="Deixe vazio para manter"></label><button class="btn btn-primary btn-block" type="submit">Salvar usuário</button></form></details><?php endif;?></td></tr><?php endforeach;?><?php if(!$users):?><tr><td colspan="5" class="empty-state">Nenhum usuário cadastrado.</td></tr><?php endif;?></tbody></table></div></section><?php if(Auth::can('users.manage')):?><aside class="stack"><form class="card sticky-card" method="post" action="<?= View::e(Router::url('/users')) ?>"><?= Csrf::input() ?><div class="section-heading"><div><span class="eyebrow">Novo acesso</span><h2>Adicionar usuário</h2></div></div><label class="field"><span>Perfil</span><select name="role"><option value="client_user">Membro da equipe</option><option value="client_admin">Administrador</option></select></label><label class="field"><span>Nome</span><input name="name" required></label><label class="field"><span>E-mail</span><input type="email" name="email" required></label><label class="field"><span>Senha inicial</span><input type="password" name="password" minlength="8" required></label><button class="btn btn-primary btn-block" type="submit">Cadastrar usuário</button></form></aside><?php endif;?></div>
